INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Unique visitor counting$q$, $q$Tracks daily unique visitors without cookies or persistent visitor identifiers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Referrer tracking$q$, $q$Shows which external sites are sending traffic to a page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Country-level geography$q$, $q$Approximates visitor location using edge network headers instead of storing IP addresses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Lightweight tracking script$q$, $q$A roughly 1.1 KB script tag keeps page-load impact minimal.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$No-cookie tracking$q$, $q$Avoids cookies, IP fingerprinting, and long-term visitor logging by design.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Self-hosting option$q$, $q$Docker-based self-hosted deployment built on Go, Redis, and SQLite.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Open-source codebase$q$, $q$Full source published on GitHub under the AGPL-3.0 license.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Free for unlimited traffic on the hosted plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$No cookie consent banner typically required due to its no-cookie approach$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Extremely small tracking script with low performance overhead$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Fully self-hostable for teams wanting complete data control$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Simple, uncluttered dashboard focused on essential metrics$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Lacks advanced segmentation, funnels, and event tracking found in full product-analytics tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$No dedicated mobile app SDK$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Support is community-driven rather than a formal enterprise contract$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Metrics are intentionally limited compared to broader analytics suites$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Is Counter free to use?$q$, $q$Yes, the hosted service at counter.dev is free with no visitor quotas, operating on a pay-what-you-want basis with optional donation tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Does Counter use cookies?$q$, $q$No, Counter is designed to avoid cookies, visitor-level logging, and IP address fingerprinting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Can I self-host Counter?$q$, $q$Yes, the project is open source under AGPL-3.0 and includes a dedicated self-hosting repository with a Docker-based setup.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$What metrics does Counter track?$q$, $q$It tracks unique daily visitors, referrer sources, and country-level location data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Does Counter support mobile app analytics?$q$, $q$No, Counter is focused on website analytics and does not offer a dedicated mobile SDK.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Privacy-conscious website owners$q$, $q$Bloggers and indie site owners who want basic traffic counts without cookie banners or personal data collection.$q$, $q$Bloggers, indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Self-hosted analytics for small teams$q$, $q$Organizations that want to run their own analytics infrastructure on inexpensive servers using the open-source self-host package.$q$, $q$Small businesses, privacy-focused teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited visitor tracking","Referrer and country data","No feature gates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$Supporter$q$, $q$From €3/month$q$, $q$monthly$q$, NULL, $q$["All hosted features","Voluntary donation to support development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Counter (counter.dev) is a simple, privacy-oriented web analytics tool built by a single independent developer and released publicly around 2020. It was created for people who want to know how many visitors their website gets, and where those visitors come from, without deploying a heavyweight analytics suite or a cookie consent banner.$q$, $q$The tool deliberately limits itself to a small set of aggregate metrics rather than trying to compete with full product-analytics platforms. It does not use cookies, does not log individual visitor behavior over time, and does not store raw IP addresses, relying instead on edge-network signals to approximate a visitor's country.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include unique daily visitor counts, referrer tracking to show which sites are sending traffic, and country-level geography, all shown on a minimal real-time dashboard. The JavaScript tracking snippet is about 1.1 KB, so it adds negligible weight to page load times.$q$, $q$The project is fully open source under the AGPL-3.0 license, with the main codebase and a separate self-hosting repository published on GitHub. Self-hosted deployments run on a Go backend with Redis for hot-tier storage and SQLite for archival data, and can be deployed via Docker on modest, low-cost server infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The hosted version at counter.dev is free with no visitor caps or gated features, operating on a pay-what-you-want model; supporters can choose optional donation tiers starting at roughly 3 euros per month. Self-hosting the open-source version is also free aside from the cost of running the small server it requires.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
