INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Session and event analytics$q$, $q$Tracks sessions, screen/page views, and custom events across web, mobile, and desktop apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Crash and error reporting$q$, $q$Collects crash and error data across iOS, Android, React Native, Flutter, Unity, and more.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Push notifications$q$, $q$Sends targeted push notifications to iOS and Android users.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Remote configuration and A/B testing$q$, $q$Lets teams adjust app behavior remotely and test variants without app store releases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Compliance Hub$q$, $q$Manages user consent and privacy-regulation compliance directly within the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Custom dashboards and reports$q$, $q$Builds tailored reports with scheduled email delivery and alerting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Self-hosting option$q$, $q$Countly can be deployed entirely on customer-owned infrastructure via the Enterprise tier or the open-source Community Edition.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Strong focus on data ownership and privacy with self-hosting options$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Combines analytics, crash reporting, and engagement tools in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Free, open-source Community Edition available for smaller teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Broad SDK coverage across mobile, web, and desktop platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Usage-based rather than seat-based pricing on the Flex plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Commercial pricing starts relatively high for smaller teams ($175/month)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Enterprise (self-hosted) tier requires custom pricing and sales contact$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Advanced personalization and AI features are add-ons on the Flex plan rather than included by default$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Self-hosting the Community Edition requires infrastructure and DevOps effort$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Is there a free version of Countly?$q$, $q$Yes, Countly Community Edition is a free, self-hosted, open-source version available on GitHub.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$How much does Countly cost?$q$, $q$Countly's Flex private-cloud plan starts at $175 per month with a 14-day free trial; the self-hosted Enterprise tier uses custom pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Where is Countly headquartered?$q$, $q$Countly is headquartered in London, United Kingdom, and operates as a fully remote, bootstrapped company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Does Countly support mobile crash reporting?$q$, $q$Yes, it collects crash and error reports across platforms including iOS, Android, React Native, Flutter, and Unity.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Can Countly be self-hosted for data privacy reasons?$q$, $q$Yes, both the Community Edition and the commercial Enterprise tier can run entirely on a customer's own infrastructure with no vendor access to data.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Mobile app product analytics$q$, $q$Product teams tracking user behavior, crashes, and engagement across iOS and Android apps.$q$, $q$Mobile app product and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Privacy-regulated industries$q$, $q$Organizations that need first-party, self-hosted analytics to meet data residency or compliance requirements.$q$, $q$Regulated enterprises, government, healthcare$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Customer engagement campaigns$q$, $q$Teams using push notifications, remote configuration, and A/B testing to drive engagement.$q$, $q$Growth and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted core analytics","Session, event, and crash reporting","Push notifications","Plugin architecture"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Flex$q$, $q$From $175/month$q$, $q$monthly$q$, NULL, $q$["Private cloud hosting","Usage-based pricing","Advanced Analytics included","Adaptivity and Intelligence available as add-ons","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Self-hosted on customer infrastructure","All capability layers included","Zero vendor access to data","Dedicated CSM and SLA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Countly is a product analytics and customer engagement platform founded in 2012 and headquartered in London, United Kingdom. The company describes itself as an independent, bootstrapped business with a fully remote team of roughly 50 or more people spread across more than 20 countries.$q$, $q$The platform combines behavioral analytics (sessions, events, funnels, cohorts), crash and error reporting, and engagement tools such as push notifications and in-app messaging, spanning web, mobile, and desktop applications. Countly emphasizes first-party data ownership, offering both a hosted product and a fully self-hostable open-source edition.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include session and event tracking, customizable dashboards and reports, crash and error reporting across major mobile and web platforms, push notifications for iOS and Android, remote configuration, A/B testing, and a Compliance Hub for consent management under regulations such as GDPR.$q$, $q$SDKs are available for iOS, Android, React Native, Flutter, Unity, Node.js, Java, and JavaScript, and the platform's read/write APIs and plugin architecture let teams extend or customize functionality. According to Countly, the platform processes data for more than 5 billion unique identities across around 126 countries for roughly 17,000 applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Countly's commercial pricing is organized into Flex, a private-cloud plan starting at $175 per month with a 14-day free trial and usage-based (not seat-based) pricing, and Enterprise, a custom-priced, self-hosted tier for organizations that need to run Countly entirely on their own infrastructure with zero vendor access to data. A free, self-hosted Community Edition is also available for teams that want core analytics without a commercial license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e67947e6-4265-4afb-9c33-f8fdf7a52909', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
