INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Requires self-managed infrastructure, MongoDB, and ongoing maintenance$q$, 1);
