INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Support relies on community forums and documentation rather than paid support$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Is Countly Community Edition really free?$q$, $q$Yes, it is free and open source under a modified AGPL-3.0 license; you only pay for the infrastructure you host it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$How is Community Edition different from Countly Flex or Enterprise?$q$, $q$Community Edition includes the core analytics engine but excludes advanced adaptivity, AI intelligence features, dedicated support, and SLAs available on paid plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$What is required to self-host Countly Community Edition?$q$, $q$A Linux server with ports 80 and 443 open; it can be installed via a one-line script on Ubuntu/CentOS or via official Docker images.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$What database does Countly Community Edition use?$q$, $q$It uses MongoDB for data storage and runs on Node.js.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Can I upgrade from Community Edition to a paid Countly plan later?$q$, $q$Yes, teams commonly start on Community Edition and later migrate to Countly's commercial Flex or Enterprise offerings as needs grow.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Self-hosted product analytics$q$, $q$Development teams wanting full control of analytics data without a subscription.$q$, $q$Startups, indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Privacy and compliance-sensitive deployments$q$, $q$Organizations with data residency or regulatory requirements that need on-premises analytics.$q$, $q$Regulated enterprises, government agencies$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Session, event, and crash analytics","Push notifications","Plugin support","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Countly Community Edition is the free, open-source, self-hosted edition of the Countly product analytics platform, maintained by London-headquartered Countly Ltd, founded in 2012. It is published on GitHub under the AGPL-3.0 license with a modified Section 7 and is one of the more established open-source analytics projects, with roughly 5,900 GitHub stars and continuous releases.$q$, $q$The Community Edition provides the same core analytics engine used across Countly's commercial products, but without the advanced personalization and AI-driven features reserved for paid Flex and Enterprise plans, making it well suited for individuals, small teams, and organizations that need self-hosted data ownership.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Community Edition includes session, view, and event tracking with built-in reports; crash and error reporting for iOS, Android, React Native, Flutter, Unity, Node.js, Java, and JavaScript; push notifications; remote configuration; in-app rating widgets; a Data Manager and Compliance Hub; and read/write APIs, all extensible through a plugin architecture.$q$, $q$The server runs on Node.js with MongoDB as its data store, deployable via a one-line installation script on Ubuntu or CentOS, or through official Docker images, requiring ports 80 and 443 to be open.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Countly Community Edition is free to download, install, and use under its open-source license, with the only ongoing cost being the infrastructure needed to host it. Teams that need advanced adaptivity or AI-driven intelligence features, dedicated support, or SLAs can upgrade to Countly's commercial Flex or Enterprise tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a59d5166-cc6a-417b-90b1-e5b6c0fb5f11', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Unified notification API$q$, $q$One API call routes messages across email, SMS, push, in-app, and chat channels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Visual notification designer$q$, $q$A web studio for building and editing message templates and flows without code changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Journeys$q$, $q$Multi-step, rule-based notification flows triggered by application events.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Broadcasts$q$, $q$One-to-many messaging for announcements and bulk notifications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$AI-assisted translations and agent node$q$, $q$Automates message localization and supports AI-driven notification logic on paid tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$MCP server and CLI$q$, $q$Supports Model Context Protocol integrations and command-line workflows for developers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Role-based access control and SLA$q$, $q$Enterprise-grade governance, observability integrations, and service-level agreements.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Consolidates many notification channels behind a single API$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Generous free tier covering up to 10,000 sends per month$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Visual designer lets non-engineers edit notification content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Usage-based pricing scales with actual notification volume$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Enterprise options include EU data residency and SLAs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Per-send pricing on the Business tier can add up at high volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Advanced AI and governance features are gated behind paid tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Adds a layer of infrastructure dependency for notification delivery$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Custom Enterprise pricing requires a sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$What does Courier do?$q$, $q$Courier is a notification infrastructure API that lets developers send email, SMS, push, in-app, and chat notifications through a single integration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$How much does Courier cost?$q$, $q$Courier's Developer tier is free for up to 10,000 sends per month; the Business tier costs $0.005 per send beyond that, and Enterprise uses custom volume pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Who founded Courier?$q$, $q$Courier was founded in 2019 by CEO Troy Goode and went through Y Combinator's Summer 2019 batch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Is Courier the same as Courier MTA?$q$, $q$No, Courier (courier.com) is a commercial notification infrastructure company, entirely separate from Courier MTA, an unrelated open-source mail server project.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Does Courier support non-technical users?$q$, $q$Yes, its web studio lets non-technical team members design and edit notification templates and flows without writing code.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Transactional and lifecycle notifications$q$, $q$Sending order confirmations, onboarding sequences, and account alerts across multiple channels.$q$, $q$Product and engineering teams at SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Multichannel alerting$q$, $q$Routing operational or incident alerts to the right channel, such as chat or SMS, based on user preference.$q$, $q$DevOps and platform teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Developer$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["Up to 10,000 sends/month","Journeys and broadcasts","MCP server, CLI and SDKs","SSO via Google/GitHub","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Business$q$, $q$$0.005 per send$q$, $q$usage-based$q$, NULL, $q$["All Developer features","AI translations and AI agent node","Email and chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Volume discounts","Dedicated Slack channel","Observability integrations","Role-based access control","Enterprise SLA","EU data residency"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Courier is a notification infrastructure platform founded in 2019 by CEO Troy Goode and headquartered in San Francisco, California. It emerged from Y Combinator's Summer 2019 batch and later raised a $35 million funding round, growing to an estimated 51-200 employees.$q$, $q$The company's core product lets developers trigger multichannel notifications, spanning email, SMS, push, in-app, and chat, through a single API call, while a visual studio lets both engineers and non-technical teammates design templates and notification flows without redeploying application code.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Courier's platform includes Journeys for multi-step notification flows, broadcasts for one-to-many messaging, an MCP server, a CLI, and SDKs for popular languages. It centralizes routing logic and user notification preferences so a single API call can determine the right channel to use.$q$, $q$Enterprise-oriented capabilities include role-based access control, observability integrations, EU data residency, and AI-assisted features such as automated translations and an AI agent notification node available on paid tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Courier prices based on notification volume rather than team size or number of channels. The free Developer tier covers up to 10,000 sends per month; the Business tier is pay-as-you-go at $0.005 per send with AI features and chat support added; and Enterprise offers custom volume-discounted pricing with SLAs, RBAC, and dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47573ceb-bc2e-4aa8-88aa-21c943d7431f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Integrated ESMTP server$q$, $q$Handles sending and receiving mail over standard SMTP/ESMTP protocols.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$IMAP and POP3 servers$q$, $q$Provides standard mailbox access protocols for email clients.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Webmail with calendaring$q$, $q$Includes a webmail interface with basic calendar and scheduling features.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Mailing list management$q$, $q$Supports mailing lists with automatic bounce processing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Flexible authentication$q$, $q$Authenticates users via PAM, LDAP, PostgreSQL, or MySQL, supporting virtual domains.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Anti-spam and security controls$q$, $q$DNS-based blacklists, SPF validation, message filtering, and TLS/SSL encryption.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Maildir storage$q$, $q$Uses the maildir format to avoid file-locking issues common with mbox stores.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Completely free and open source under the GPL$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Combines SMTP, IMAP, POP3, webmail, and mailing lists in one framework$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Highly configurable, with components that can be enabled or disabled independently$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Long-running project with a multi-decade development history$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Strong RFC compliance and standards-based security features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Requires significant system administration expertise to install and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$No commercial support, managed hosting, or vendor SLA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Documentation and community are smaller than more popular MTAs like Postfix$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$User interface and tooling feel dated compared to modern managed email platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Is Courier MTA free?$q$, $q$Yes, Courier MTA is free, open-source software distributed under the GNU General Public License.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Is Courier MTA the same company as Courier (courier.com)?$q$, $q$No, they are unrelated. Courier MTA is an open-source mail server project dating to 1998; Courier (courier.com) is a separate, venture-backed notification API company founded in 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$What protocols does Courier MTA support?$q$, $q$It supports ESMTP, IMAP, POP3, LDAP, SSL/TLS, and HTTP for webmail, along with mailing list management.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$What operating systems does Courier MTA run on?$q$, $q$It compiles on most POSIX-based systems, including Linux and BSD-derived kernels, as well as Solaris and AIX.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Does Courier MTA support virtual mail domains?$q$, $q$Yes, it supports virtual mail accounts and domains authenticated via LDAP, MySQL, or PostgreSQL.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Self-hosted email infrastructure$q$, $q$System administrators running their own mail servers instead of using a third-party hosted email service.$q$, $q$System administrators, hosting providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$Combined mail and webmail deployment$q$, $q$Organizations wanting SMTP, IMAP/POP3, and webmail access in a single consistent server framework.$q$, $q$Small ISPs, self-hosting enthusiasts$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Courier MTA is a free, open-source, integrated mail and groupware server created by developer S. Varshavchik, with the project's history dating back to 1998 and continuing to receive updates. It is licensed under the GNU General Public License and hosted on GitHub as a shared repository for its various sub-projects.$q$, $q$Unlike single-purpose mail transfer agents, Courier combines ESMTP, IMAP, POP3, webmail, and mailing list functionality in one consistent framework, letting administrators enable only the components they need for a given deployment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Courier supports authentication via PAM, LDAP, PostgreSQL, or MySQL, virtual mail domains and accounts, maildir-based storage, DNS-based blacklists, SPF validation, message filtering, and TLS/SSL encryption. Its webmail module includes basic calendaring and scheduling.$q$, $q$The project favors strict RFC compliance over legacy Sendmail-style conventions, rejecting malformed messages rather than accommodating them, and compiles on most POSIX systems including Linux, BSD derivatives, Solaris, and AIX.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Courier MTA is free and open source under the GPL, with no commercial licensing tiers. Organizations bear only the cost of the infrastructure and system administration time needed to self-host and maintain it.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d0165e6b-299a-413e-8603-112e26c2317d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$University and industry partnerships$q$, $q$Courses and credentials produced with universities like Stanford and Yale, and companies like Google and IBM.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Specializations and Professional Certificates$q$, $q$Multi-course sequences and employer-recognized certificate programs in high-demand skills.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Accredited online degrees$q$, $q$Full bachelor's and master's degree programs delivered online through university partners.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Coursera Plus subscription$q$, $q$Unlimited access to most of the course catalog for a flat monthly or annual fee.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Free auditing option$q$, $q$Lets learners access video lectures and materials for free without a certificate.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Coursera for Business/Teams$q$, $q$Organizational licensing for employee upskilling with team management and reporting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Graded assignments and peer review$q$, $q$Auto-graded quizzes and peer-reviewed assignments to assess learning.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Wide selection of courses from well-known universities and companies$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Free auditing option for cost-conscious learners$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Accredited degree programs available fully online$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Coursera Plus offers strong value for learners taking multiple courses$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Recognized Professional Certificates from major technology employers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Degree programs can be significantly more expensive than individual courses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Free auditing does not include certificates or graded assignments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Coursera Plus does not include every course, degree, or specialization on the platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Team pricing may be costly for very small organizations$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Who founded Coursera?$q$, $q$Coursera was founded in 2012 by Stanford professors Andrew Ng and Daphne Koller.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Is Coursera free?$q$, $q$Most courses can be audited for free without a certificate; paid options include individual course purchases, Coursera Plus, and degree programs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$How much is Coursera Plus?$q$, $q$Coursera Plus costs $59 per month or $399 per year for unlimited access to most of the course catalog.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Does Coursera offer full degrees?$q$, $q$Yes, Coursera partners with accredited universities to offer online bachelor's and master's degree programs, ranging from about $3,750 to $49,440.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$What is Coursera for Business?$q$, $q$It is Coursera's organizational learning offering, priced at $399 per user per year for teams of 5 to 125 users, with custom Enterprise pricing for larger organizations.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Career upskilling$q$, $q$Individuals learning new technical or business skills through courses and Professional Certificates.$q$, $q$Career changers, job seekers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Accredited online degrees$q$, $q$Students pursuing a full bachelor's or master's degree remotely through university partners.$q$, $q$Degree-seeking students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Corporate learning and development$q$, $q$Organizations licensing Coursera for Business to train and upskill employees at scale.$q$, $q$L&D teams, HR departments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Audit$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Access to video lectures and reading materials","No certificate or graded assignments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Individual Course/Specialization$q$, $q$$49-$99$q$, $q$one-time$q$, NULL, $q$["Certificate included","Graded assignments","Lifetime access to purchased content"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Coursera Plus$q$, $q$$59/month or $399/year$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited access to most courses and Specializations","Certificates included","Access to most Professional Certificates"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Coursera for Teams$q$, $q$$399/user/year$q$, $q$annual$q$, NULL, $q$["For 5-125 users","25% nonprofit discount","Team management and reporting"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$Degrees$q$, $q$$3,750-$49,440$q$, $q$program-dependent$q$, NULL, $q$["Accredited bachelor's or master's degree","University-issued credentials"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Coursera was founded on April 18, 2012, by Stanford professors Andrew Ng and Daphne Koller and is headquartered in Mountain View, California. The company is publicly traded on the New York Stock Exchange under the ticker COUR and had reached approximately 205 million cumulative registered learners as of its Q1 2026 financial reporting.$q$, $q$The platform partners with universities and companies to deliver courses, Specializations, Professional Certificates, and accredited online degrees across fields such as technology, data science, business, and health.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Coursera offers video-based courses with quizzes and graded assignments, peer review for certain coursework, Specializations that bundle related courses, Professional Certificates from companies like Google and IBM, and full bachelor's and master's degree programs delivered online through accredited university partners.$q$, $q$The platform also includes Coursera for Business and Coursera for Teams for organizational learning, along with AI-assisted features for coaching and content translation introduced in recent years.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Most courses can be audited for free without a certificate. Individual courses or Specializations typically cost $49 to $99 with certificate access, while Coursera Plus offers unlimited catalog access for $59 per month or $399 per year. Degree programs range from about $3,750 to $49,440, and Coursera for Teams costs $399 per user annually for organizations of 5 to 125 users, with custom Enterprise pricing above that.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ac9ab5c-4a63-4bad-ba6c-e9edf649f3f5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
