INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Cross-platform native apps$q$, $q$Available on macOS, iOS, iPadOS, Windows, Android, and web.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$AI writing assistance$q$, $q$AI-assisted editing and writing with tiered access to different AI model levels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Real-time collaboration$q$, $q$Multiple users can edit and comment on documents together.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Shareable document links$q$, $q$Publishes polished, web-page-style or PDF-like versions of documents for external sharing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Version history$q$, $q$Retains prior document versions, from 7 days on the free plan up to 30 days on Plus.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Offline-first sync$q$, $q$Designed to work offline with sync across devices once reconnected.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Polished, native apps across Mac, iOS, Windows, and Android$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Generous free tier with a functional AI credit allotment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Affordable Plus pricing compared to bundling several separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Strong visual design and document sharing formatting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Family and Team plans make multi-user pricing straightforward$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Free plan is capped at 1,500 content blocks and 1 GB storage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$AI credits are limited even on the Plus plan (50/month)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Less suited to complex relational databases than tools like Notion or Airtable$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Team plan tops out at 10 accounts before requiring a custom sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Is Craft free to use?$q$, $q$Yes, Craft has a free tier with 1,500 content blocks, 1 GB of storage, and limited AI credits; paid plans remove these caps.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$What platforms does Craft support?$q$, $q$Craft is available on macOS, iOS, iPadOS, Windows, Android, and as a web app.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Who makes Craft?$q$, $q$Craft is developed by Luki Labs Limited, founded in 2019 by Balint Orosz and headquartered in Budapest, Hungary.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$How much does Craft Plus cost?$q$, $q$Craft Plus starts at €4.80 per month when billed annually, or €8.00 per month billed monthly.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Does Craft include AI features?$q$, $q$Yes, Craft includes AI-assisted writing and editing, with the number of monthly AI credits and available AI models varying by plan.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Personal notes and journaling$q$, $q$Individuals capturing notes, journals, and personal documents across devices.$q$, $q$Individual users, students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Team knowledge bases$q$, $q$Small teams building shared documentation and collaborating on project notes.$q$, $q$Small teams, startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Shareable client documents$q$, $q$Creating polished, shareable documents and proposals that resemble formatted web pages or PDFs.$q$, $q$Freelancers, consultants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Free$q$, $q$€0/month$q$, $q$N/A$q$, NULL, $q$["1,500 content blocks","1 GB storage","25 MB media upload limit","7-day version history","15 monthly AI credits"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Plus$q$, $q$€4.80/month (annual) or €8.00/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited content and storage","Unlimited media uploads","30-day version history","50 monthly AI credits","Access to Core, Fast, and Max AI models"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Family$q$, $q$€9.00/month$q$, $q$monthly or annual$q$, NULL, $q$["Bundles 2-6 Plus accounts","Shared collaboration space"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$Team$q$, $q$€50.00/month$q$, $q$monthly$q$, NULL, $q$["Bundles up to 10 Plus accounts","Shared collaboration space","Custom options for larger groups"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Craft is a notes, documents, and task app developed by Luki Labs Limited, founded in 2019 by Balint Orosz and headquartered in Budapest, Hungary. It launched first on iOS and iPadOS, later expanding to macOS, Windows, Android, and the web, and was named Apple's Mac App of the Year in 2021.$q$, $q$The company has raised institutional funding, including an $8 million Series A round led by Creandum and a subsequent $12 million Series B round, supporting continued development of its cross-platform document editor and, more recently, AI-assisted writing features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Craft's editor is block-based, letting users build structured notes, documents, and tasks with nested pages and cards, emphasizing visual design and native platform performance. It supports real-time collaboration, shareable document links formatted like polished web pages or PDFs, and offline-first sync across devices.$q$, $q$AI features include writing and editing assistance, with the number of monthly AI credits and available model tiers (Core, Fast, Max) varying by subscription plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Craft's Free plan includes 1,500 content blocks, 1 GB storage, and 15 monthly AI credits. The Plus plan starts at €4.80/month (billed annually) with unlimited content and storage plus 50 AI credits. Family (€9.00/month) bundles 2-6 Plus accounts, and Team (€50.00/month) bundles up to 10 Plus accounts, with custom pricing for larger groups.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c7ea5abe-ea46-4e4c-b5e4-246810a1c777', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
