INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Custom content modeling$q$, $q$Lets developers define custom content types, fields, and structures per project instead of using fixed templates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Twig-based templating engine$q$, $q$Flexible front-end templating for building custom-designed sites.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$GraphQL API$q$, $q$Provides a headless GraphQL API for decoupled front ends, available on Team and Pro.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Plugin ecosystem$q$, $q$An official plugin store extends Craft with commerce, forms, SEO, and other functionality.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Multi-site and multi-locale support$q$, $q$Manages multiple sites and languages from a single Craft installation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Live preview and image editor$q$, $q$Built-in tools for previewing content changes and editing images in the control panel.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Two-factor authentication and passkeys$q$, $q$Modern authentication options for securing the control panel.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Highly flexible content modeling suited to custom, design-driven websites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Free Solo edition available for personal projects and evaluation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Source-available codebase allows full inspection and extension$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Team and Pro licenses become free when hosted on Craft Cloud$q$, 3);
