INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Not free for production use beyond the single-user Solo edition$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Requires PHP development expertise, unlike no-code website builders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$License renewal fees apply annually for continued updates$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Smaller plugin and developer ecosystem than more widely used CMS platforms like WordPress$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Is Craft CMS free?$q$, $q$The Solo edition is free but limited to one admin user account; Team and Pro editions require a paid license for multi-user production use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Is Craft CMS open source?$q$, $q$Its source code is publicly available on GitHub under a BSD-3-Clause license, but a commercial license is required to run Team or Pro editions in production, making it source-available rather than fully free/open source in production use.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$How much does Craft CMS cost?$q$, $q$Team costs $279 for the first year ($99 annual renewal) and Pro costs $399 for the first year ($99 annual renewal); both are free when hosted on Craft Cloud.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Who makes Craft CMS?$q$, $q$Craft CMS is made by Pixel & Tonic, an independent software company founded in 2013 and headquartered in Bend, Oregon.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Does Craft CMS support headless use?$q$, $q$Yes, Team and Pro editions include a GraphQL API for headless, decoupled front-end architectures.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Custom agency websites$q$, $q$Digital agencies building bespoke, design-driven websites for clients with unique content structures.$q$, $q$Web design and development agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Headless content delivery$q$, $q$Organizations using Craft's GraphQL API to power decoupled front ends built with frameworks like Next.js.$q$, $q$Development teams building headless architectures$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Solo$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["One user account","Unlimited content types, entries, pages, and locales","Asset management, multi-site, live preview"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Team$q$, $q$$279 (first year), $99/year renewal$q$, $q$annual$q$, NULL, $q$["Up to 5 user accounts","One user group","Developer support","All Solo features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Pro$q$, $q$$399 (first year), $99/year renewal$q$, $q$annual$q$, NULL, $q$["Unlimited user accounts and groups","Branded control panel","GraphQL API","All Team features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["SAML SSO","Custom agreements","Procurement support","Dedicated premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Craft CMS is a flexible, PHP-based content management system built by Pixel & Tonic, an independent company founded in 2013 and headquartered in Bend, Oregon. Unlike CMS platforms built around fixed themes or content structures, Craft lets developers define custom content types and fields for each project, making it a popular choice for bespoke, design-led websites.$q$, $q$The full codebase is open and available on GitHub under a BSD-3-Clause license, but running Craft in production beyond the free Solo tier requires a commercial license, placing it in an open-core, source-available licensing category.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Craft CMS includes a Twig-based templating engine, a GraphQL API, an extensive official plugin store, multi-site and multi-locale support, live preview, an integrated image editor, two-factor authentication and passkey support, and GDPR-oriented compliance tools across all editions.$q$, $q$User management capabilities scale with the license tier: Solo supports a single admin account, Team supports up to five user accounts and one user group, and Pro supports unlimited user accounts and groups along with a brandable control panel.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35e4bc85-6298-43d3-bc27-0854ea063792', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Craft CMS Solo is free for self-hosted projects with a single user account. Team is $279 for the first year ($99 annual renewal), and Pro is $399 for the first year ($99 annual renewal). Team and Pro licenses are free when a site is hosted on Craft Cloud, the company's managed hosting platform, and a custom-priced Enterprise tier adds SAML SSO and premium support.$q$]::text[], 2);
