-- Enrichment marathon batch: Counter, Countly, Countly Community Edition, Courier, Courier MTA, Coursera, Craft, Craft CMS

-- ── Counter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Counter (counter.dev) is a minimalist, privacy-first web analytics tool that tracks unique visitors and referrers without cookies, logging, or IP fingerprinting.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (pay-what-you-want)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Solo-maintained open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Counter (counter.dev): Privacy-First Web Analytics$q$, seo_title),
  seo_meta_description = COALESCE($q$Counter (counter.dev) is a free, privacy-friendly web analytics tool with no cookies or IP tracking. See features, pricing, and self-hosting options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Counter, published at counter.dev, is a lightweight, privacy-first web analytics tool created by solo developer Irae Hueck Costa (GitHub handle ihucos) and released around 2020. It was built as a minimalist alternative to Google Analytics for site owners who want basic visitor counts without collecting personal data. Counter explicitly avoids cookies, visitor-level logging, and IP address fingerprinting; instead it relies on aggregate edge signals, such as Cloudflare's country-detection header, to approximate visitor geography without ever storing an IP address. The hosted service at counter.dev is free to use on a pay-what-you-want basis: there is a permanent free tier with no visitor quotas or feature gates, and users who want to support development can opt into voluntary donation tiers starting around 3 euros per month via PayPal. The tracking script is extremely small, roughly 1.1 KB, keeping page-load impact minimal compared with heavier analytics suites. Counter's dashboard focuses on a narrow set of core metrics: unique daily visitors, referrer sources showing which sites link in, and country-level location data, presented in a simple, uncluttered interface rather than the deep funnel and cohort analysis found in enterprise analytics platforms. The full source code is published on GitHub under the ihucos/counter.dev repository, licensed under the GNU Affero General Public License v3 (AGPL-3.0), and a companion self-hosting repository, ihucos/counter.dev-selfhost, provides a Docker-based setup so organizations can run their own instance instead of using the hosted service. The self-hosted stack runs on Go, Redis as the primary hot-tier database, and SQLite for cold archival storage, designed to run efficiently on inexpensive infrastructure; the maintainer has described serving millions of monthly unique visits from a single virtual server costing about five dollars a month. Because Counter does not use cookies or track individuals across sites, it is frequently positioned as a privacy-regulation-friendly option for bloggers, indie developers, small business sites, and privacy-conscious organizations that want basic traffic insight without needing a cookie consent banner. It does not offer the advanced segmentation, event tracking, A/B testing, or product-analytics features found in tools like Countly, Mixpanel, or Google Analytics 4; it is intentionally scoped to simple, aggregate website traffic counting rather than full product analytics. There is no dedicated mobile SDK, no e-commerce tracking, and no built-in advertising attribution, so teams needing those capabilities typically pair Counter with another tool or choose a broader analytics platform instead. Support is community-driven through GitHub issues and public discussion threads rather than a formal enterprise support contract, reflecting its indie, single-maintainer origins. In practice, Counter's value proposition is being a just-the-numbers analytics tool: fast to install with a single script tag, transparent about what it does and does not collect, free for unlimited traffic on the hosted plan, and fully open source for teams that want complete data ownership through self-hosting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ef53c4a7-0fd5-4507-9b35-ef5053bbcf0e';

