-- ── Countly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Countly is a first-party product analytics and customer engagement platform offering web, mobile, and desktop analytics with a strong focus on data privacy.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Flex plans from $175/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$50+ employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Countly: Product Analytics & Engagement Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Countly is a privacy-focused product analytics platform for web, mobile, and desktop apps. Compare pricing, features, and its open-source Community Edition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Countly is a product analytics and customer engagement platform founded in 2012, with its headquarters registered in London, United Kingdom. The company describes itself as an independent, bootstrapped business that has grown to roughly 50 or more employees working remotely across 20-plus countries. Countly's platform tracks sessions, screen and page views, custom events, crash and error reports, and user segments across web, mobile, and desktop applications, then surfaces that data through built-in reports, customizable dashboards, and scheduled email reports and alerts. Beyond core analytics, Countly offers customer engagement capabilities such as push notifications for iOS and Android, in-app rating widgets, remote configuration, A/B testing, and a Compliance Hub for consent and privacy-regulation management. According to the company, its infrastructure processes data for more than 5 billion unique identities across roughly 126 countries and powers around 17,000 applications, running on approximately 3,000 servers worldwide. Countly is distinctive for offering both a hosted commercial product and a free, self-hosted open-source edition called Countly Community Edition, published on GitHub under a modified AGPL-3.0 license; the commercial tiers layer additional capabilities such as advanced adaptivity (personalization and remote configuration at scale) and AI-assisted intelligence features on top of the open-source core. As of its current pricing structure, Countly organizes its commercial offering into two primary tracks: Flex, a private-cloud plan starting at $175 per month with a 14-day free trial, priced on usage rather than seats, hosted in a secure private cloud with selectable regions, and Enterprise, a self-hosted, custom-priced tier for organizations that need to deploy Countly on their own infrastructure with zero vendor access to underlying data, enterprise-grade security and compliance certifications, dedicated customer success management, and a service-level agreement. Both commercial tracks are built around three capability layers Countly calls Advanced Analytics (included in both plans), Adaptivity (an add-on on Flex, included in Enterprise), and Intelligence (an add-on on Flex, included in Enterprise), letting customers start with core analytics and expand into personalization and AI-driven insights as needed. Historically, Countly also offered lower-cost cloud tiers around $69 and $189 per month for smaller session volumes, though its published pricing has since shifted toward the current Flex and Enterprise structure. Countly positions itself against alternatives like Google Analytics, Mixpanel, and Amplitude primarily on data ownership and privacy: because the Community Edition and Enterprise tier can both run entirely on a customer's own infrastructure, organizations in regulated industries, or those wanting first-party control of sensitive user data, are a core part of its target audience alongside product teams that want mobile crash reporting, push notifications, and behavioral analytics in one platform. Its SDKs cover a broad range of platforms including iOS, Android, React Native, Flutter, Unity, Node.js, and JavaScript for the web, and its server-side stack is built on Node.js and MongoDB, extensible through a plugin architecture.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e67947e6-4265-4afb-9c33-f8fdf7a52909';

