-- ── Countly Community Edition ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Countly Community Edition is the free, open-source, self-hosted version of the Countly product analytics platform, licensed under a modified AGPL-3.0.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$50+ employees (Countly)$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Countly Community Edition: Free Self-Hosted Analytics$q$, seo_title),
  seo_meta_description = COALESCE($q$Countly Community Edition is a free, open-source, self-hosted product analytics platform with session tracking, crash reporting, and push notifications.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Countly Community Edition is the free, open-source, self-hosted version of the Countly product analytics and engagement platform, maintained by Countly Ltd, a company founded in 2012 and headquartered in London, United Kingdom. It is published on GitHub in the countly-server repository under the AGPL-3.0 license with a modified Section 7, and as of recent counts has accumulated around 5,900 stars, nearly 1,000 forks, over 200 releases, and tens of thousands of commits, indicating an actively maintained project. The Community Edition gives individuals and small teams core analytics functionality without a commercial license: session, view, and event collection with built-in reporting; crash and error reporting across platforms such as iOS, Android, React Native, Flutter, Node.js, Unity, Java, and JavaScript; push notifications for iOS and Android; remote configuration; in-app rating widgets; customizable dashboards; scheduled email reports and alerts; a Data Manager for planning event schemas; a Compliance Hub for consent management; user and application management; and read/write APIs for custom integrations, all extensible through a plugin-based architecture. Technically, the server is built on Node.js and stores data in MongoDB, running on Linux, with a frontend built largely in JavaScript, HTML, CSS, and SCSS. Installation is designed to be straightforward: Countly provides a one-line bash installation script for Ubuntu and CentOS, official Docker images for containerized deployment, and documentation covering manual setup, with the main requirement being that ports 80 and 443 be reachable. Because it is self-hosted, Community Edition gives organizations full ownership of the underlying data with no reliance on Countly's cloud infrastructure, which makes it attractive to teams with strict data residency, privacy, or compliance requirements, as well as to individual developers and startups who want product analytics without a recurring subscription cost. The tradeoff is that Community Edition does not include the advanced adaptivity (personalization, large-scale remote configuration) and AI-driven intelligence features that Countly reserves for its commercial Flex and Enterprise tiers, and running it requires a team to provision, secure, and maintain its own server infrastructure, MongoDB database, and updates rather than relying on a managed cloud service. Community support is available through Countly's community forums, GitHub issues, and documentation, but without the dedicated customer success management or service-level agreements that come with paid plans. In practice, Community Edition functions as both a free entry point into the Countly ecosystem, letting teams evaluate the platform before considering an upgrade to Flex or Enterprise, and as a viable long-term solution for organizations with the technical capacity to self-host and whose analytics needs are met by its core feature set. It supports the same broad range of client SDKs as the commercial editions, so mobile, web, and desktop applications can all be instrumented using a consistent tracking approach regardless of which Countly edition is ultimately used.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a59d5166-cc6a-417b-90b1-e5b6c0fb5f11';

