-- ── Courier ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Courier is a notification infrastructure platform that lets developers send email, SMS, push, chat, and in-app notifications through a single API and visual designer.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 10,000 sends/month), then $0.005 per send$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Courier: Multichannel Notification API for Developers$q$, seo_title),
  seo_meta_description = COALESCE($q$Courier is a notification infrastructure platform for sending email, SMS, push, and in-app messages through one API. See pricing, features, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Courier is a notification infrastructure platform founded in 2019 by CEO Troy Goode and headquartered in San Francisco, California. Backed by Y Combinator (batch S19) and having raised a $35 million funding round reported in 2022, the company employs roughly 51 to 200 people. Courier's core value proposition is consolidating the many notification channels an application might use, including email, SMS, push notifications, in-app messages, and chat integrations like Slack and Microsoft Teams, behind a single API and a visual notification designer, rather than requiring developers to integrate separately with providers such as SendGrid, Twilio, and Firebase Cloud Messaging for each channel. Developers call Courier's API to trigger a notification, and Courier handles routing the message to the right channel or channels based on rules, user preferences, and delivery logic configured in Courier's web studio, which is also usable by non-technical team members to design and edit message templates and multi-step notification flows called Journeys without redeploying code. The platform includes broadcasts for one-to-many messaging, an MCP (Model Context Protocol) server, a command-line interface, and SDKs for common languages and frameworks. Pricing is structured around notification volume rather than team size or number of channels used: the free Developer tier includes up to 10,000 sends per month along with Journeys, broadcasts, the MCP server, CLI and SDK access, single sign-on via Google or GitHub, and email support. Beyond the free allotment, the Business tier is usage-based at $0.005 per notification sent, adding AI-assisted translations, an AI agent notification node, and email plus chat support. An Enterprise tier offers custom, volume-discounted pricing along with a dedicated Slack channel for support, observability integrations, role-based access control, an enterprise SLA, and EU data residency options for organizations with stricter compliance needs. Courier is aimed primarily at product and engineering teams building consumer or B2B SaaS applications that need reliable, centralized notification delivery, for use cases such as transactional alerts, onboarding sequences, marketing-adjacent lifecycle messages, and operational alerts, without building and maintaining bespoke integrations for every channel and provider. Because pricing and access to advanced features (AI translation, AI agent nodes, RBAC, SLAs) scale with the Business and Enterprise tiers, smaller teams and side projects can operate entirely on the free tier for lower notification volumes, while growing companies pay incrementally as their notification volume increases. It is worth noting explicitly that Courier the notification-infrastructure company (courier.com) is an entirely separate product from Courier MTA (courier-mta.org), an unrelated open-source mail transfer agent and groupware server first developed in the late 1990s; the two share a name but have no corporate or technical relationship.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '47573ceb-bc2e-4aa8-88aa-21c943d7431f';

