-- ── Courier MTA ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Courier MTA is an open-source, integrated mail and groupware server providing ESMTP, IMAP, POP3, webmail, and mailing list services under the GPL.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1998, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Courier MTA: Open-Source Mail Server & Groupware$q$, seo_title),
  seo_meta_description = COALESCE($q$Courier MTA is a free, open-source integrated mail server offering ESMTP, IMAP, POP3, webmail, and mailing list services for POSIX systems.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Courier MTA, published at courier-mta.org, is an open-source, integrated mail transfer agent and groupware server originally created by developer S. Varshavchik, with copyright notices on the project spanning from 1998 through recent years, indicating a long-running project with over two decades of continuous development. It is distributed under the GNU General Public License and its source code is hosted on GitHub under svarshavchik/courier, which serves as a shared repository for the various Courier-related sub-projects. Rather than being a single-purpose mail transfer agent like Postfix or Exim, Courier bundles several mail and groupware services into one consistent framework: an ESMTP server for sending and receiving mail, IMAP and POP3 servers for mailbox access, a webmail interface with basic calendaring and scheduling functionality, and mailing list management with automatic bounce processing. Individual components can be enabled or disabled independently, so an administrator can run Courier purely as an SMTP relay, purely as an IMAP/POP3 mailbox server, or as a full combined mail and webmail platform depending on their needs. Authentication can be handled through PAM, LDAP, PostgreSQL, or MySQL, and the server supports virtual mail domains and accounts backed by those same authentication sources rather than requiring local Unix system accounts for every mailbox. Security and anti-spam features include DNS-based blacklist checking, Sender Policy Framework (SPF) validation, message filtering, and TLS/SSL support for encrypted mail delivery and access. Courier natively stores mail using the maildir format, which is designed to avoid file-locking problems and corruption common with older mbox-based mail stores, while still offering legacy mbox support for compatibility. The project deliberately omits certain legacy Sendmail-era conventions, such as per-user .forward files and the ETRN command, in favor of stricter RFC compliance, and it will reject malformed messages that violate email standards rather than attempt to work around them. Courier compiles on most POSIX-based operating systems, including Linux and BSD-derived kernels, with additional support for Solaris and AIX using vendor-supplied freeware tools. Because it is free, self-hosted, and has no commercial vendor, Courier MTA is primarily used by system administrators, hosting providers, and organizations that want to run their own mail infrastructure without relying on a third-party email service or paying per-mailbox licensing fees. It requires more hands-on system administration expertise than a managed email service, since operators are responsible for installation, configuration, security hardening, and ongoing maintenance themselves. Courier MTA should not be confused with Courier (courier.com), an unrelated venture-backed SaaS company founded in 2019 that provides a commercial multichannel notification API for sending email, SMS, push, and chat notifications from applications; the two products share a name only by coincidence and have no shared codebase, company, or history.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd0165e6b-299a-413e-8603-112e26c2317d';

