-- ── Coursera ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Coursera is a global online learning platform offering courses, Specializations, Professional Certificates, and degrees from universities and companies worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free to audit; Coursera Plus from $59/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$1,400+ employees$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Coursera: Online Courses, Certificates & Degrees$q$, seo_title),
  seo_meta_description = COALESCE($q$Coursera offers online courses, Professional Certificates, Specializations, and degrees from top universities and companies. See pricing and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Coursera is an online learning platform founded on April 18, 2012, by Stanford University computer science professors Andrew Ng and Daphne Koller, and headquartered in Mountain View, California. The company went public on the New York Stock Exchange under the ticker COUR in 2021 and, as of Q1 2026 reporting, had reached roughly 205 million cumulative registered learners worldwide, adding a first-quarter record of 7.6 million new registered learners in that period. Coursera's workforce is globally distributed, with concentrations in San Francisco, Toronto, Bengaluru, New York, Mountain View, Delhi, London, Gurugram, and Washington DC, totaling well over 1,000 employees. The platform partners with universities (including Stanford, Yale, Duke, and the University of Michigan) and companies (including Google, IBM, Meta, and Microsoft) to publish courses, Specializations (multi-course sequences), Professional Certificates, MasterTrack modules, and full online degree programs spanning bachelor's and master's levels. Content covers technology, data science, business, health, and personal development, among other fields, delivered through video lectures, quizzes, peer-reviewed and auto-graded assignments, and, increasingly, AI-assisted coaching and translation features. Coursera's pricing operates on several tiers. Individual learners can audit most courses for free, viewing lecture videos and reading materials without receiving a certificate or graded assignments. Single courses and Specializations can also be purchased individually, typically in the range of $49 to $99, which includes the certificate and full access to graded work. Coursera Plus is the platform's primary subscription, priced at $59 per month or $399 per year, granting unlimited access to the majority of Coursera's catalog of courses, Specializations, and Professional Certificates. Full online degree programs, offered in partnership with accredited universities, range much higher, from roughly $3,750 up to about $49,440 depending on the institution and program. For organizations, Coursera for Business (branded Coursera for Teams for smaller groups) serves teams of 5 to 125 users at $399 per user per year, with a 25% discount available to registered nonprofits, while larger organizations with 125 or more users, or those needing advanced administrative and reporting features, move to a custom-priced Enterprise plan. Coursera's target audience spans individual career changers and skill-builders, university students seeking credentialed degrees online, and corporate learning and development teams purchasing licenses for employee upskilling. Its competitive position sits alongside platforms like edX (now part of 2U), Udemy, LinkedIn Learning, and Pluralsight, differentiated primarily by its deep university partnerships, accredited degree offerings, and large catalog of employer-recognized Professional Certificates from major technology companies.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
