-- ── Craft ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Craft is a notes, docs, and task app by Luki Labs featuring a block-based editor, AI writing assistance, and native apps for Mac, iOS, Windows, and Android.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free; Plus from €4.80/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small (startup, Series B funded)$q$, company_size),
  headquarters = COALESCE($q$Budapest, Hungary$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Craft: Notes, Docs & AI Writing App by Luki Labs$q$, seo_title),
  seo_meta_description = COALESCE($q$Craft is a block-based notes and docs app with AI writing tools, available on Mac, iOS, Windows, and Android. Compare Craft's features and pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Craft is a notes, documents, and task-management app developed by Luki Labs Limited, founded in 2019 by Balint Orosz and headquartered in Budapest, Hungary. The product, often referred to as Craft Docs in its early years, launched first on iOS and iPadOS before expanding to macOS, and has since added Windows, Android, and web versions, giving it native or near-native coverage across all major desktop and mobile platforms. Craft was named Apple's Mac App of the Year in 2021, and the company has raised institutional funding including an $8 million Series A round led by Creandum (described in coverage as backed partly by former Skyscanner executives) and a later $12 million Series B round. The product's core interaction model is a block-based document editor, similar in spirit to tools like Notion, that lets users structure notes, documents, and tasks using nested blocks, cards, and pages, with strong emphasis on visual polish, native platform feel, and offline-first performance rather than a purely web-based experience. Craft supports real-time collaboration, document sharing via public links, custom formatting for creating shareable documents that resemble PDFs or web pages, and cross-device sync. In recent years Craft has added AI-assisted features, including AI writing and editing help, with access to different AI model tiers depending on the subscription plan. Craft's pricing is structured as a freemium subscription. The free tier allows up to 1,500 content blocks, 1 GB of storage, a 25 MB per-file media upload limit, 7-day version history, and a limited allotment of 15 monthly AI assistant credits with access to only the more basic AI models. The Plus plan, priced at €4.80 per month when billed annually or €8.00 per month billed monthly, removes the content and storage caps, extends version history to 30 days, increases the AI credit allotment to 50 per month, and unlocks access to more capable AI models. A Family plan at €9.00 per month bundles two to six Plus accounts together with a shared collaboration space, and a Team plan at €50.00 per month bundles up to ten Plus accounts for larger groups, with custom options available by contacting sales beyond that size. Craft positions itself in marketing as a lower-cost alternative to combining several separate subscription tools, citing example comparisons of roughly $46 per month for equivalent functionality elsewhere versus its own Plus pricing. The app's target users are individuals and small teams who want a visually polished, cross-platform notes and documentation tool with native apps rather than a browser-only experience, spanning use cases from personal journaling and meeting notes to team knowledge bases and shared project documentation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c7ea5abe-ea46-4e4c-b5e4-246810a1c777';

