-- ── Craft CMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Craft CMS is a flexible, source-available PHP content management system by Pixel & Tonic, built for custom-designed websites with a free Solo edition and paid licenses.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / One-time license + subscription (Craft Cloud)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Solo); Team from $279, Pro from $399$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Small (independent software company)$q$, company_size),
  headquarters = COALESCE($q$Bend, Oregon, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Craft CMS: Flexible PHP Content Management System$q$, seo_title),
  seo_meta_description = COALESCE($q$Craft CMS is a flexible, source-available PHP CMS by Pixel & Tonic for custom websites. Compare Solo, Team, and Pro pricing, features, and hosting options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Craft CMS is a flexible, PHP-based content management system created and maintained by Pixel & Tonic, an independent software company founded in 2013 and headquartered in Bend, Oregon. Rather than shipping with a fixed theme system or predefined content structure like many CMS platforms, Craft CMS lets developers define custom content types, fields, and structures (called sections and entry types) tailored to a specific website or application, which has made it popular for bespoke, design-driven websites and digital platforms built by agencies and freelance developers rather than as an out-of-the-box blogging or storefront tool. Craft CMS follows an open-core, source-available licensing model: its full codebase is publicly hosted on GitHub under a BSD-3-Clause license, so the code can be inspected, audited, and extended by anyone, but running Craft in a production environment beyond the free Solo edition requires purchasing a commercial license. The platform's control panel, templating engine (built on Twig), GraphQL API, plugin ecosystem, and core content-modeling tools are consistent across all editions, with licensing tiers primarily gating user-management capabilities and branding options rather than core functionality. Pricing for self-hosted deployments is structured as per-project licenses rather than recurring subscriptions in the traditional sense: the Solo edition is free and includes unlimited content types, entries, pages, and locales but is limited to a single admin user account, making it suitable for personal projects, prototypes, or learning; the Team edition costs $279 for the first year (with a $99 annual renewal for continued updates) and adds up to five user accounts and one user group; and the Pro edition costs $399 for the first year (also $99 annual renewal) and adds unlimited user accounts and groups, a brandable control panel, GraphQL API access, and other capabilities suited to professional client work. Notably, Craft's Team and Pro licenses become free when a site is hosted on Craft Cloud, the company's own managed hosting platform, with Craft Cloud itself billed according to its own hosting-tier pricing rather than the license fee. An Enterprise tier offers custom pricing for organizations that need SAML single sign-on, custom contractual agreements, procurement support, and dedicated premium support. All editions share features such as asset management, multi-site support, built-in search, live preview, an image editor, two-factor authentication, passkey support, GDPR-oriented compliance tooling, and access to the official plugin store. Craft CMS is primarily used by digital agencies, freelance developers, and organizations that need a highly customizable content backend for marketing sites, publishing platforms, and other content-heavy digital products where a rigid, template-locked CMS would be too limiting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '35e4bc85-6298-43d3-bc27-0854ea063792';

